class Solution {
public:
  int maxEquationalWindows(vector<vector<int>>& jobs, vector<vector<int>>& windows) {
    int n = jobs.size(), m = windows.size();
    sort(jobs.begin(), jobs.end());
    sort(windows.begin(), windows.end());
    int ans = 0, j = 0;
    for (int i = 0; i < m; i++) {
      if (windows[i][0] <= jobs[j][1]) {
        ans++;
        i++;
      } else if (j < n - 1 && jobs[j + 1][0] <= windows[i][0]) {
        ans++;
        j++;
      } else {
        ans--;
      }
      j = max(j, i);
    }
    return ans;
  }
};

